sys_script_include.script:
var AN_ScanManager = Class.create();

AN_ScanManager.prototype = {

    runScan: function(scanId) {

        try {

            gs.info('Scan Started');

            new AN_ACLScanner().scan(scanId);

            new AN_BRScanner().scan(scanId);

            new AN_ScriptScanner().scan(scanId);

            new AN_PerfScanner().scan(scanId);

            new AN_UpdateSetScanner().scan(scanId);

            new AN_GradeCalculator().calculate(scanId);

			new AN_BenchmarkEngine().evaluate(scanId);

			new AN_AIAdvisor().analyze(scanId);

            gs.info('Scan Complete');

        } catch (ex) {

            gs.error('ScanManager Error: ' + ex);
        }
    },

    type: 'AN_ScanManager'
};
